package corejava;
// continue : Skip the iteration if the variable i is 6, but continue with the next iteration:
public class continuekeywords {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		
		 for ( int i= 1; i<=10; i++) {
			 if(i==6) {
				  continue;
				
			 }
			 System.out.println(i);
		 }
	}

}
